var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"코핀 오브 아스모데우스… 최초 가동일로부터 ■■■일 경과.","JPN":"コフィン・オブ・アスモデウス……初稼働から■■■日経過。","ENG":"Coffin of Asmodeus... ■■■ days passed since initial operation.","TWN":"阿斯蒙蒂斯之棺……自最初啟動日算起 ■■■天後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"균열의 침식파 유출량 및 클리파 오염 농도 점진적으로 상승 중-","JPN":"亀裂の侵食波流出量およびクリファ汚染濃度、徐々に上昇中……","ENG":"Corruption rays from the crevice and Qlipha contamination density gradually increasing.","TWN":"裂隙中流出的侵蝕波濃度及逆卡巴拉污染度逐漸上升中——"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"임계치까지 남은 예상 시간… 472시간.","JPN":"臨界値までの予想残り時間……472時間。","ENG":"Estimated time until critical point... 472 hours.","TWN":"距離達到臨界點剩餘……472小時。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"하늘이 참 붉네요.","JPN":"空が真っ赤ですね。","ENG":"The sky bleeds crimson.","TWN":"天空真紅啊。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"마치 세상의 마지막 날처럼 불타는 것 같아요.","JPN":"まるで世界最後の日のように燃えているようであります。","ENG":"It's as if it knows the end is about to unfold.","TWN":"就像世界末日一樣燃燒著。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"우리가 늘 보아왔던 평범한 석양이다.","JPN":"私たちがいつも見てきた普通の夕暮れだ。","ENG":"It is the same ordinary sunset we've always seen.","TWN":"這就是我們一直看到的普通夕陽……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"하지만, 저 붉은 빛이 우리의 적수를 떠올리게 한다는 건 부정할 수 없군.","JPN":"だが、あの赤い光が私たちの敵を思い出させるのは否定できないな。","ENG":"But I can't deny that the red hue reminds me of our enemy.","TWN":"但是那個紅光……確實會讓人想起我們現在的對手。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그 마왕의 이명… 잿더미의 여왕이라고 했던가요.","JPN":"あの魔王の異名……灰の女王といいましたか？","ENG":"That Demon Lord's alias... wasn't it the Queen of Ashes?","TWN":"那個魔王的別名……好像有人把她叫作灰燼女王吧？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"삼대국이 연합하여 결성한 북부 전선을 고작 이틀만에 무너트렸다죠.","JPN":"三大国が連合して結成した北部戦線をたった2日で滅ぼしたとか。","ENG":"They say that even the northern front formed by the three great powers fell in just two days.","TWN":"聽說三個大國聯合組成的北部戰線僅僅兩天就被她擊潰了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"그래. 그 어떤 계략이나 농간도 없이 순수한 무력으로 부딪혀서 말이야.","JPN":"そうだ。なんの戦略も、企みもなく純粋に武力だけでぶつかってきたんだ。","ENG":"Yes. And it was by pure force, without any tricks or gimmicks.","TWN":"對。沒有任何陰謀詭計，只有純粹的武力對決。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"우리가 관을 가동하지 않았다면, 지금쯤 온 대륙이 잿더미 아래에 자취를 감췄겠지.","JPN":"私たちが棺を稼働していなかったら、今頃全大陸が灰の下に消えていただろう。","ENG":"If we didn't activate the Coffin, the whole continent would be buried in ashes by now.","TWN":"如果我們沒有啟動棺材，現在整片大陸早已化為灰燼了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"하지만 아무것도 해결된 건 없어요. 관은 시간을 벌기 위한 임시방편일 뿐이잖아요.","JPN":"ですが、解決されたことは何もありません。棺はただの時間稼ぎにすぎないではないですか。","ENG":"But nothing has been resolved. This Coffin is just a temporary measure to buy some time.","TWN":"但什麼都沒有解決。那個棺材只是為了爭取時間的臨時措施而已。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"그거면 충분하다!","JPN":"それで十分なのだ！","ENG":"That's more than enough!","TWN":"那就足夠了!"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L18_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"덕분에 우린 무사히 대적자와 만났고, 늑대를 훌륭한 전사로 키워냈으니까!","JPN":"おかえげ私たちは無事敵対者と出会い、オオカミを立派な戦士に育て上げたではないか！","ENG":"Thanks to it, we safely met with the Antagonist and raised the Wolf into a great warrior!","TWN":"多虧如此，我們才能順利撐到與對手會面，並將狼培養成了出色的戰士！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"당신이 아니라 힐데 씨가 가르친 거죠.","JPN":"君ではなく、ヒルデさんが育てたんでしょう。","ENG":"It was Hilde who raised the Wolf, not you.","TWN":"不是我們，培養了狼的人是希爾德。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"우리가 그 괴물을 상대로… 정말 이길 수 있을까요?","JPN":"私たちがあの化け物を相手に……本当に勝てるのでしょうか。","ENG":"Do you think we can win... against that monster?","TWN":"你真的覺得……我們真的能打贏那種怪物嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"율리아 전대장.","JPN":"ユリア戦隊長。","ENG":"Commander Yulia.","TWN":"茱莉亞隊長。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"그대는 이 세상을 구하기 위해 무엇을 걸 수 있지?","JPN":"君はこの世界を救うために何を賭ける？","ENG":"What are you willing to risk in order to save the world?","TWN":"你能為拯救這個世界付出什麼？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"…전부 다요.","JPN":"……すべてです。","ENG":"...Everything.","TWN":"……全部……嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"이길 수만 있다면 내 목숨이라도 바칠 거예요.","JPN":"勝てるのであれば、自分の命さえ捧げます。","ENG":"I'll give my life if it means that we can win.","TWN":"只要能贏，我願意獻出我的生命。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"좋은 각오다!","JPN":"いい覚悟だ！","ENG":"Excellent determination!","TWN":"很好的覺悟！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L30_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"그 각오만 무너지지 않는다면 우린 이길 거다! 반드시!","JPN":"その覚悟さえ健在なら、私たちは勝つ！　必ず！","ENG":"I'm certain we'll win as long as that determination doesn't break!","TWN":"只要這種覺悟不動搖，我們就會贏！一定會贏！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"대화를 할 때마다 그렇게 얼굴을 들이미셔야 하나요?","JPN":"話すたびにそうやって、顔を近づけないといけないんでしょうか？","ENG":"Do you always have to get all up in my face when we talk?","TWN":"我們每次說話的時候，你都有必要湊這麼近嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"흐음… 밥이나 먹으러 가죠.","JPN":"ふむ……食事でもしに行きましょうか。","ENG":"Hmm... Let's go eat something.","TWN":"哈……我們去吃點東西吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"당신의 그 기합도 좋지만, 굶으면 싸울 기운도 안 날 테니까요.","JPN":"君のその気合もいいけど、腹が減っては戦う力がでないのであります。","ENG":"I admire your spirit, but we won't have the energy to fight if we don't eat.","TWN":"我很佩服你的那股幹勁，但如果餓著肚子的話，就沒力氣戰鬥了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"좋은 생각이군!","JPN":"いい考えだな！","ENG":"Good thinking!","TWN":"好主意！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"관리국의 각 전대는 각자의 역할에 맞춰 움직인다.","JPN":"管理局の各戦隊は各々の役割に従って動く。","ENG":"Each division of the Administration mobilizes according to their respective roles.","TWN":"管理局的各個戰隊各司其職就行了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"사령부의 지시는 돌발 변수에 대응하기 위한 것일 뿐, 기본적으로 전투는 전대 지휘권자의 재량과 능동적인 판단에 맡기고 있지.","JPN":"司令部の指示は突発的な変数に対応するためだけであり、基本的に戦闘は戦隊の指揮権者の裁量と能動的な判断に任せている。","ENG":"The orders from the Command are there for responding to unexpected variables, and battles are basically left to the discretion and active judgment of the division Commander.","TWN":"指揮部的指示只是為了應對突發情況，戰鬥基本上還是交給各戰隊長的自主裁量和判斷。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"저, 스승님.","JPN":"あの、師匠。","ENG":"Um, Master.","TWN":"嗯……師父。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"그럼 전 어느 전대에 속하게 되는 건가요?","JPN":"では、私はどの戦隊の所属になるんですか？","ENG":"Then, which division do I belong to?","TWN":"那我會被分配到哪個戰隊呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"넌 전대에 속할 필요가 없다, 파블린.","JPN":"お前は戦隊に所属する必要はない、パブリン。","ENG":"You don't need to be in a division, Pavlin.","TWN":"你不需要加入戰隊，帕芙琳。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"네 역할은 대적자로서 마왕과 맞서는 것이고, 우리와 함께 할 테니까.","JPN":"お前の役割は敵対者として魔王に立ち向かうことであり、私たちも行動をともにする。","ENG":"Your role as the Antagonist is to fight the Demon Lord, and we will be with you.","TWN":"你的角色是作為敵對者與魔王對抗，並且會和我們一起行動。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"제가… 마왕을 이길 수 있을까요? 전 스승님처럼 검을 휘두를 줄도 모르는데…","JPN":"私が……魔王に勝てるんでしょうか？　私は師匠みたいに剣を振るうこともできませんが……","ENG":"Can I... win against the Demon Lord? I don't even know how to swing a sword like you, Master...","TWN":"我……能打敗魔王嗎？我不像師父那樣會揮劍……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"걱정 마라.","JPN":"心配するな。","ENG":"Don't worry.","TWN":"別擔心。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"너에겐 클리파차원을 간섭하는 특별한 재능이 있지.","JPN":"お前にはクリファ次元に干渉できる特別な才能がある。","ENG":"You have a special talent for interfering with the Qlipha dimension.","TWN":"你有干涉逆卡巴拉次元的特殊才能。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"언젠가 벌어질 결전에서, 마왕으로 향하는 길을 열게 될 거다.","JPN":"いつか繰り広げられる決戦で、魔王への道を開くことになるだろう。","ENG":"In the battle that will take place one day, you will pave the way to the Demon Lord.","TWN":"總有一天，在即將到來的決戰中，你將打開通向魔王的通道。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"늑대의 이빨이 마왕의 심장에 박힐 수 있도록.","JPN":"オオカミの牙を魔王の心臓に突き刺すことができるように。","ENG":"So that the Wolf's fangs can puncture the Demon Lord's heart.","TWN":"好讓狼牙刺入魔王的心臟。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"알겠어요.","JPN":"わかりました。","ENG":"Okay.","TWN":"我明白了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"최선을 다해볼게요, 스승님.","JPN":"頑張ってみます、師匠。","ENG":"I'll try my best, Master.","TWN":"我會盡全力的，師父。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"그렇게 부르지 말라고 했을 텐데? 난 네 스승이 아니야.","JPN":"そう呼ぶなと言ったはずだ。私はお前の師匠ではない。","ENG":"I told you not to call me that. I am not your master.","TWN":"我說過不用那麼叫我吧？我不是你的師父。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"난 너에게 검술을 가르쳐준 적도 없고, 가르쳐줄 생각도 없어.","JPN":"私はお前に剣術を教えたこともないし、教えるつもりもない。","ENG":"I have not and will not teach you swordsmanship.","TWN":"我從未教過你劍術，也不打算教你。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"너의 그 타고난 허약체질로 검을 휘둘렀다간 마왕은커녕 들고양이에게도 당할 거다.","JPN":"その生まれつきひ弱な体で剣など振るったら、魔王はおろか野良猫にさえやられるだろう。","ENG":"Swinging a sword with your weak physical constitution, you won't be able to defeat a stray cat, let alone a Demon Lord.","TWN":"你的體質天生太虛弱了，揮起劍來別說是魔王，連路邊的一隻野貓都無法打倒。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"에헤헤… 들고양이가 좀 무섭긴 하죠.","JPN":"えへへ……野良猫って怖いですよね。","ENG":"Eh he he... Stray cats can be kinda scary.","TWN":"嘿嘿嘿，野貓……確實有點嚇人呢。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"그래도, 전 계속 스승님이라고 부를래요.","JPN":"でも、私はずっと師匠って呼びます。","ENG":"But still. I'm going to keep calling you Master.","TWN":"不過，我還是想繼續叫你師父。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"스승님은 관리국과 함께 혜성처럼 나타나 침식으로부터 저희 세계를 구하고…","JPN":"師匠は管理局と一緒に彗星のように現われて、侵食から私たちの世界を救って……","ENG":"You appeared out of the blue with the Administration and saved our world from Corruption...","TWN":"師父與管理局一同如彗星般出現，拯救了我們的世界免受侵蝕……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"아무것도 모르고 겁도 많던 저에게 이 힘을 올바르게 쓰는 법을 가르쳐 주셨으니까요.","JPN":"何もわからなくて臆病者だった私に、この力の正しい使い方を教えてくれたんですから。","ENG":"Above all, you taught me, this timid person who knew nothing of the world, how to use my powers for good.","TWN":"最重要的是，你教會了我這個什麼都不懂、又膽小的傢伙如何正確使用自己的力量。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"…마음대로 해라.","JPN":"……好きにしろ。","ENG":"...Do as you please.","TWN":"……隨便你吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"하지만 착각하지 마. 우린 너를 돕는 것일 뿐, 이 세계를 구하는 건 전적으로 네 몫이다.","JPN":"だが、勘違いするな。私たちはお前を助けているだけで、この世界を救うのはあくまでお前の役目だ。","ENG":"But don't be mistaken. We are merely helping you. It's entirely up to you to save this world.","TWN":"但是別誤會。我們只是幫你，拯救這個世界完全是你的責任。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"목숨을 함부로 하지 말고, 포기해서도 안돼. 알겠나?","JPN":"命を粗末にするな。諦めるのもダメだ。わかったか？","ENG":"You mustn't be careless with your life or give it up. Do you understand?","TWN":"不要隨便玩命，也不要輕易就放棄。明白了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"네.","JPN":"はい。","ENG":"I do.","TWN":"好的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"제 힘으로, 이 세계를 구하겠어요.","JPN":"私の力で、この世界を救います。","ENG":"I will save this world with my powers.","TWN":"用我的力量，拯救這個世界。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"결국 시작되고 말았군.","JPN":"結局始まっちゃったね。","ENG":"So, it has finally begun.","TWN":"終於開始了。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"마왕이 움직이기 전에 놈의 힘을 방주로 틀어 막을 수도 있었을 텐데 말이지.","JPN":"魔王が動く前に、やつの力を箱舟で封印することもできたはずなのに。","ENG":"We could've used the Ark to contain the Demon Lord's power before she made her move.","TWN":"你知道的吧？在魔王行動前，我們本可以用方舟封住她的力量。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"방주를 희생 시켜 시간을 버느냐, 방주를 이용해 마왕을 공격하느냐.","JPN":"箱舟を犠牲にして時間を稼ぐか、箱舟を利用して魔王を攻撃するか。","ENG":"Buy time by sacrificing the Ark, or use it to attack the Demon Lord.","TWN":"是犧牲方舟來爭取時間，還是利用方舟削弱魔王。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"난 그 중 후자를 택했을 뿐이야.","JPN":"私は後者を選んだだけさ。","ENG":"I chose the latter.","TWN":"我只是選擇了後者而已。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"클리포트 게임을 정면으로 맞서는 건 처음이잖아.","JPN":"クリフォトゲームを真っ向勝負するのは初めてじゃん。","ENG":"Isn't it your first time facing a Qliphoth Game head-on?","TWN":"這可是你第一次正面迎戰逆卡巴拉遊戲啊。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"WRITER_TIME_NULL_NULL","text":{"KOREA":"공격하면, 이길 가능성은 있어?","JPN":"攻撃したら、勝つ可能性はある？","ENG":"Do you think we have a chance to win if we attack?","TWN":"你的意思是攻擊的話，我們的勝算會更大嗎？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"가능성은 언제나 있어왔지.","JPN":"可能性はいつもでもあったさ。","ENG":"The possibilities have always existed.","TWN":"可能性一直都在。"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"대적자와 늑대 그리고 관리국의 이름으로 얻을 수 있는 모든 수단이 한 자리에 모였으니, 지금보다 더 희망적인 상황이 어딨겠나.","JPN":"敵対者とオオカミ、それに管理局の名で手に入れられるすべての方策が1か所に集まったんだ、今ほど希望的な状況はない。","ENG":"All means available under the Administration, the Antagonist, and the Wolf have all gathered in one place. This is as hopeful as it can get.","TWN":"敵對者與狼，還有以管理局的名義能使用的一切手段都聚集在這裡了，還有什麼比現在更有希望的情況嗎？"},"stage":{"bg":"SKY_RED","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WRITER_TIME_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"느껴져. 마왕이 가까워지고 있어.","JPN":"感じる。魔王が近づいてる。","ENG":"I can feel it. The Demon Lord is approaching.","TWN":"我能感覺到，魔王在接近了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOLF_NPC_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"상관없다. 이쪽도 마찬가지로 나아갈 테니까.","JPN":"構わん。こちらも同じく進んでいるからな。","ENG":"No matter. For we must also move forward.","TWN":"無所謂。我們也在繼續前進。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"규칙은 제대로 숙지했겠지?","JPN":"ルールはちゃんと熟知しているだろうな？","ENG":"Have you familiarized yourself with the rules?","TWN":"你應該熟悉規則了吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"그럭저럭.","JPN":"なんとか。","ENG":"More or less.","TWN":"多少熟悉了點……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOLF_NPC_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"힐데. 긴장되지 않아?","JPN":"ヒルデ。緊張しない？","ENG":"Hilde. Aren't you nervous?","TWN":"希爾德。你不緊張嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOLF_NPC_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"어차피 맞설 수 밖에 없는 싸움이다.","JPN":"どのみち避けられない戦いだ。","ENG":"It's a fight we had to face one day.","TWN":"反正是無法避免的戰鬥。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"무슨 수를 써서든 이기겠다는 생각뿐이야.","JPN":"どんな手を使ってでも勝ってやると思っているだけだ。","ENG":"All I'm thinking about is a way to win at any cost.","TWN":"我只想著無論用什麼手段都要贏。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"후훗, 역시 힐데답네.","JPN":"ふふっ、ヒルデらしい。","ENG":"Haha, that's so you, Hilde.","TWN":"呵呵，不愧是希爾德。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOLF_NPC_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"파블린은 어때?","JPN":"パブリンはどう？","ENG":"How are you, Pavlin?","TWN":"帕芙琳呢？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOLF_NPC_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"북의 폭군은 제 고향을 불태웠고, 머잖아 온 세상을 전부 불바다로 만들겠죠.","JPN":"北の暴君は自分の故郷を焼き払い、近いうち全世界を火の海にするでしょう。","ENG":"The Tyrant of the North burned down my home. Soon, she'll set aflame the entire world.","TWN":"北方暴君燒毀了我的家鄉，不久之後她就會把整個世界都變成火海。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"그 자를 쓰러뜨리는 데 보탬이 될 수만 있다면…","JPN":"あの者を倒すのに役立つことができるなら……","ENG":"If I can be of help in stopping her...","TWN":"只要能幫上忙打倒她……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"제 목숨도 아깝지 않아요.","JPN":"私の命だって惜しくないんです。","ENG":"I will gladly offer my life for it.","TWN":"即使是我的生命也不足惜。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"쓰러트릴 거야.","JPN":"倒す。","ENG":"She will go down.","TWN":"一定會打倒她的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOLF_NPC_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"그러기 위해서 여기까지 온 거니까.","JPN":"そのためにここまで来たんだから。","ENG":"That is why we're here.","TWN":"這就是我們來這裡的原因。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_CS_AMBIENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOLF_NPC_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"subtitle","speaker":null,"text":{"KOREA":"오퍼레이션 <color=#ffd34c>클리포트 게임</color> 최종국면 \\nCSE Lv. 5","JPN":"オペレーション<color=#ffd34c>クリフォトゲーム</color>最終局面\\nCSE Lv.5","ENG":"Operation <color=#ffd34c>Qliphoth Game</color> Final Phase\\nCSE Lv. 5","TWN":"作戰<color=#ffd34c>逆卡巴拉遊戲</color>，最終階段\\nCSE Lv. 5"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"subtitle","speaker":null,"text":{"KOREA":"관측된 신성 클리파 타입- 아스모데우스.","JPN":"観測された神聖クリファタイプ-アスモデウス。","ENG":"Observed Divinity Qlipha Type- Asmodeus.","TWN":"觀測到神聖逆卡巴拉類型——阿斯蒙蒂斯。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"개전 1시간 10분 경과.","JPN":"開戦から1時間10分経過。","ENG":"1 hour 10 minutes since the start of the battle.","TWN":"距離作戰開始已經過1小時10分鐘。"},"stage":{"bg":"MAINSTREAM_000002","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_SYS_RUNNING"},{"id":"L8_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"가용병력의 87%를 상실. 최전선 붕괴까지 앞으로 15분 미만 추정.","JPN":"可動兵力の87％を喪失。最前線崩壊まであと15分未満推定。","ENG":"87% of all available units are lost. Time until the forefront collapses is estimated to be under 15 minutes.","TWN":"可用兵力損失87%。預計前線將在15分鐘內崩潰。"},"stage":{"bg":"MAINSTREAM_000002","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 마왕좌 또한 머지 않았어.","JPN":"だが、魔王の座はもうすぐだ。","ENG":"But the Demon Lord's throne is not far away.","TWN":"但距離魔王的王座也不遠了。"},"stage":{"bg":"MAINSTREAM_000002","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"저 사도 둘의 발을 묶을 수만 있다면… 늑대는 무사히 마왕에게 닿을 수 있겠지.","JPN":"あの2人の使徒の足を止めることさえできれば……オオカミは無事魔王にたどり着けるだろう。","ENG":"If only we could keep those two Apostles occupied... the Wolf would be able to safely reach the Demon Lord.","TWN":"只要能束縛住那兩個使徒的腳步……狼就能順利到達魔王那裡。"},"stage":{"bg":"MAINSTREAM_000002","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"현재 지휘체계가 정상 동작하는 전대는 둘로 확인됩니다.","JPN":"現在指揮体制が正常に作動している戦隊は2つと確認されました。","ENG":"There are currently two divisions under proper command and control.","TWN":"目前確認到有兩支戰隊指揮系統尚且正常。"},"stage":{"bg":"MAINSTREAM_000002","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L13_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"두 전대가 길을 열 때까지 사도의 움직임을 봉쇄할 수 있습니다.","JPN":"両戦隊が道を開くまで使徒の動きを封じることができます。","ENG":"The two divisions can obstruct the Apostles' movements until the path is cleared.","TWN":"可使用該戰隊開路，封鎖使徒行動，"},"stage":{"bg":"MAINSTREAM_000002","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"작전에 투입될 두 전대의 생환 가능성은 얼마나 되지?","JPN":"作戦に投入される両戦隊が生還する可能性はどのくらいだ？","ENG":"What is the likelihood of the two divisions returning safely if they were to be deployed?","TWN":"投入作戰的兩個戰隊生還的可能性有多大？"},"stage":{"bg":"MAINSTREAM_000002","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"타깃에 대한 데이터가 부족합니다.","JPN":"ターゲットについてのデータが足りません。","ENG":"There is insufficient data on the target.","TWN":"缺少目標資料。"},"stage":{"bg":"MAINSTREAM_000002","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L16_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"특이변수가 발생하지 않는 한, 전멸할 것으로 예측됩니다.","JPN":"特異変数が発生しないかぎり、全滅すると予測されます。","ENG":"Unless an outlier occurs, they are expected to be annihilated.","TWN":"若非出現特殊變數，預計將全滅。"},"stage":{"bg":"MAINSTREAM_000002","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MAINSTREAM_000002","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"계속 정체되고 있어.","JPN":"ずっと停滞してる。","ENG":"They keep trying to block me.","TWN":"這樣一直停滯在原地。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOLF_NPC_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"침식체들이 이렇게 몰려와서야, 나아가기 쉽지 않네.","JPN":"侵食体がこんなに押し寄せてくると、前に進むのは難しい。","ENG":"With all these C.O.s coming at me like this, I can't easily move forward.","TWN":"侵蝕體一直湧過來，無法輕易前進。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOLF_NPC_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"지원포격이 멈췄군. 전부 당한 건가.","JPN":"支援砲撃が止まったな。全部やられたのか。","ENG":"The supporting artillery seems to have stopped. Have they all been wiped out?","TWN":"支援炮擊停止了，難道全軍覆沒了嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"분명 놈이 있는 곳까지 얼마 남지 않았을 텐데…","JPN":"きっとやつがいるところまでそう遠くないはずだが……","ENG":"I'm certain that we're almost there...","TWN":"我們離那個傢伙肯定也不遠了……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"제가 아스모데우스의 사도들을 붙잡아둘게요! 그동안 두 분이 앞으로 나아가세요!","JPN":"私がアスモデウスの使徒を止めてみます！　その間に2人は前に進んでください！","ENG":"I'll keep Asmodeus' Apostles distracted! In the meantime, you two should go ahead!","TWN":"我會拖住阿斯蒙蒂斯的使徒！你們兩位趁機前進吧！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"무모한 짓이다. 그랬다간 우리가 마왕에게 닿기 전에 네가 먼저 죽어.","JPN":"無茶だ。それでは私たちが魔王にたどり着く前にお前が先に死ぬぞ。","ENG":"That's reckless. If we do that, you'll die before we get to reach the Demon Lord.","TWN":"太魯莽了。這麼做的話，在我們接近魔王之前你就會先死。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"여기까지 오려고 이미 많은 사람들이 희생됐어요!","JPN":"ここまで来るためにすでに多くの人たちが犠牲になったんです！","ENG":"Too many have already been sacrificed to get here!","TWN":"為了走到這裡，已經有很多人犧牲了！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"이제 와서 포기할 순 없잖아요!","JPN":"今さら諦めるわけにはいかないでしょう！","ENG":"We can't turn back now!","TWN":"現在放棄可不行啊！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"진정해, 파블린. 너무 무리하게 행동하면 오히려 남은 기회마저 잃고 말 거야.","JPN":"落ち着いて、パブリン。無茶な行動をとると、むしろ残っていたチャンスまで失うことになるよ。","ENG":"Calm down, Pavlin. Acting recklessly will only result in losing whatever chances we have left.","TWN":"冷靜點，帕芙琳。太過勉強的話，反而會失去為數不多的機會。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOLF_NPC_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"게다가… 당신에겐 이제 지켜줘야 할 생명이 하나 더 있잖아?","JPN":"それに……あなたには今や守るべき命がもう1人いるでしょ？","ENG":"Besides... you're responsible for another life now, remember?","TWN":"而且……你現在還有一個需要守護的生命，不是嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOLF_NPC_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"스승님! 위험해요!","JPN":"師匠！　危ないです！","ENG":"Master! Look out!","TWN":"師父！危險！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"칫, 귀찮게 이터까지 꼬여 든 건가?","JPN":"ちっ、面倒くさい。イーターまで絡んで来たか？","ENG":"Tch! There's even an Eater now? What a bother.","TWN":"哼，真是麻煩，連暴食都來了？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"어라…?","JPN":"あれ……？","ENG":"Huh...?","TWN":"咦……?"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"침식체 몸통에 커다란 구멍이…?","JPN":"侵食体の胴体に大きな穴が……？","ENG":"There's a huge hole in the C.O.'s body...","TWN":"侵蝕體身上有個大洞……？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"강습함의 차원도약? 저걸로 침식체를 들이받았다고?","JPN":"強襲艦の次元跳躍？　あれで侵食体に突っ込んだのか？","ENG":"A dimension jump from an Assault Ship? Someone charged into a C.O. with that?","TWN":"是強襲戰艦的次元跳躍嗎？用那種方式撞擊了侵蝕體？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOLF_NPC_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"저런 무식한 짓을 벌일 녀석은 하나 밖에 없군.","JPN":"あんな無茶をするやつは1人しかいない。","ENG":"There's only one who's stupid enough to do something like this.","TWN":"能做出那種愚蠢行為的傢伙只有一個。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"여기는 라만차 돌격전대의 전대장 오러…!","JPN":"こちら、ラマンチャ突撃戦隊の戦隊長、オーラ……！","ENG":"This is Commander Aura of the La Mancha Stormtrooper Division...!","TWN":"這裡是拉曼查突擊戰隊的隊長，奧蘿……！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"사령부의 지시를 받고 도우러왔다!","JPN":"司令部の指示で助けに来た！","ENG":"We've come to help after receiving orders from the Command!","TWN":"我們接到指揮部的指示來幫忙了！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"네놈의 조준이 조금만 빗나갔으면 나까지 휘말렸을 거다, 오러.","JPN":"貴様の照準が少しでもずれていたら私まで巻き込まれるところだった、オーラ。","ENG":"I would have been injured if your aim had been slightly off, Aura.","TWN":"你瞄準得稍微偏一點的話，我也會被捲進去的，奧蘿。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"괜찮다! 계획은 내가 세웠지만, 차원도약의 좌표 설정은 조종에 일가견 있는 율리아가 맡아줬으니까!","JPN":"大丈夫！　計画を立てたのは私だが、次元跳躍の座標設定は優れた操縦の腕を持つユリアが担当してくれたからな！","ENG":"It's fine! I may have devised this plan, but my skilled pilot Yulia was in charge of inputting the coordinates for the dimension jump!","TWN":"沒關係！雖然計畫是我制定的，但次元跳躍的座標設置是由擅長操控的茱莉亞負責的！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"시렌 추격전대의 율리아. 저희도 늑대를 도우라는 명령을 받고 왔어요.","JPN":"シレン追跡戦隊のユリア。私たちもオオカミを助けろという命令で来ました。","ENG":"This is Yulia of the Sirin Tracking Division. We have also come with orders to help the Wolf.","TWN":"賽蓮追擊戰隊的茱莉亞。我們也接到幫助狼的命令而來了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L6_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"다행이야. 다들 무사했구나.","JPN":"よかった。みんな無事だったんだ。","ENG":"Thank goodness. They are all safe.","TWN":"真是太好了！你們都沒事。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOLF_NPC_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"다른 전대는 전부 전멸에 가까운 타격을 입었어요.","JPN":"他の戦隊はすべて全滅に近いダメージを受けました。","ENG":"The other divisions are nearly wiped out.","TWN":"其他戰隊受到攻擊幾乎全軍覆沒。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L9_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"저희와 합류를 기대하는 건 어려울 겁니다.","JPN":"私たちとの合流を期待するのは難しいと思われます。","ENG":"It will be difficult to expect them to join us.","TWN":"他們恐怕無法來與我們會合。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"그럴 수가…","JPN":"そんな……","ENG":"That can't be...","TWN":"怎麼會……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"고작 이 짧은 사이에 많은 분들이… 그렇게 허무하게…","JPN":"この短い間にたくさんの人たちが……そんなあっけなく……","ENG":"In just that brief moment, all those people... died in vain...","TWN":"在這麼短的時間裡，許多人……就這樣白白地……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"분한 건 알지만 침착해야 돼, 파블린.","JPN":"悔しいのはわかるけど落ち着いて、パブリン。","ENG":"I understand your anger, but you must stay calm, Pavlin.","TWN":"我知道你很憤怒，但請冷靜，帕芙琳。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOLF_NPC_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"이 싸움의 마지막과 세계의 운명은 살아남은 우리에게 달려있으니까.","JPN":"この戦いの最後と世界の運命は、生き残った私たちにかかってるんだから。","ENG":"Because we, the survivors, decide the outcome of this fight and the fate of the world.","TWN":"這場戰鬥的結局和世界的命運都取決於我們這些倖存者。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WOLF_NPC_PAST_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MOM_NPC_BIRDCAGE_NULL","text":{"KOREA":"네… 알고 있어요.","JPN":"はい……わかってます。","ENG":"Yes... I'm aware.","TWN":"嗯……我知道了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"잠깐. 사령부에서 우릴 도우라고 했다고?","JPN":"待て。司令部から私たちを助けるように言われただと？","ENG":"Hold on. The Command told you to help us?","TWN":"等一下，是指揮部請你們來幫忙的嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"그렇다! 사도들의 발을 묶어 둘 전력이 필요하다더군!","JPN":"そうだ！　使徒の足を止める戦力が必要だとな！","ENG":"Correct! They told us that you would need units to hold off the Apostles!","TWN":"沒錯！他們說你們需要能牽制住使徒的力量！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"파블린 양의 차원분리 능력을 빌려 두 사도를 작은 공간에 고립시키고, 저희 두 전대가 각자 놈들을 맡게 될 거예요.","JPN":"パブリン君の次元分離能力を借りて使徒たちを小さな空間に孤立させ、私たち両戦隊がそれぞれやつらを引き受けるんです。","ENG":"We will isolate the two Apostles in a small space by borrowing Pavlin's dimension-splitting ability, and our two divisions will each take on one of them.","TWN":"借助帕芙琳小姐的次元分離能力，將兩名使徒隔離在小空間內，由我們兩支隊伍分別對付他們。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"그렇게 한다면 사도들의 발을 확실히 묶을 수는 있겠군.","JPN":"そうすれば確かに使徒の動きを封じることができるな。","ENG":"That does sound like a surefire way to keep the Apostles busy.","TWN":"這樣一來，確實可以牢牢束縛住使徒們的行動。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"하지만 마찬가지로 너희들의 퇴로마저 묶이게 된다. 알고는 있나?","JPN":"だが、お前たちの退路も封鎖されることになる。わかっているのか？","ENG":"But that will also block your escape routes. Do you understand what that means?","TWN":"但是同樣地，你們的退路也會被封鎖。你明白嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"AURA_ADMIN_NULL_HELMET","text":{"KOREA":"걱정마라! 우린 후퇴 따윈 하지 않아!","JPN":"心配するな！　私たちは退却などしない！","ENG":"Don't worry! Retreat is not an option for us!","TWN":"別擔心！我們從不退縮！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L25_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"그게 안전하고 정상적인 작전이었다면, 사령부의 패러독스 씨가 플랜B라는 표현을 쓰지도 않았겠죠.","JPN":"それが安全で正常な作戦だったのなら、司令部のパラドックスさんがプランBという表現を使うことはなかったはずです。","ENG":"If this were a safe and normal operation, the Command's Paradox wouldn't have called it \\"Plan B.\\"","TWN":"要是這個計畫安全且正常，指揮部的悖論就不會用B計畫這個詞了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L26_1","type":"dialog","speaker":"COMMANDER_PAST_JULIA_NULL","text":{"KOREA":"이게 세상을 구하기 위한 최선의 방법이라면… 저희는 그 지시에 따를 뿐이에요.","JPN":"これが世界を救うための最善の方法なら……私たちはその指示に従うだけです。","ENG":"If this is the best way to save the world... we will follow through with the orders given to us.","TWN":"如果這是拯救世界的最佳方法……我們會遵從指示。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AURA_ADMIN_NULL_HELMET","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"…알겠다.","JPN":"……わかった。","ENG":"...Understood.","TWN":"……明白了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HILDE_FENRIR_ADMIN_SILHOUETTE","text":{"KOREA":"그럼 그쪽은 너희에게 맡기지.","JPN":"では、そっちはお前たちに任せよう。","ENG":"Then, we'll leave those two to you.","TWN":"那這邊的事情就交給你們了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_ADMIN_SILHOUETTE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"…사도들의 시그니처 파형이 차례대로 소실됐습니다.","JPN":"……使徒たちのシグネチャー波形が順番に消失されました。","ENG":"...The Apostles' signature waveforms have sequentially disappeared.","TWN":"……使徒們的標誌性波形已依次消失。"},"stage":{"bg":"MAINSTREAM_000002","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L34_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"사도 격리에 성공한 것을 확인.","JPN":"使徒の隔離に成功したことを確認。","ENG":"We have confirmed that the Apostle isolation was a success.","TWN":"確認成功隔離使徒。"},"stage":{"bg":"MAINSTREAM_000002","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"예상 격리 유지 시간은 20분입니다.","JPN":"予想される隔離維持時間は20分です。","ENG":"The estimated isolation time is 20 minutes.","TWN":"預計隔離維持時間為，20分鐘。"},"stage":{"bg":"MAINSTREAM_000002","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이걸로… 마지막 한 계단만이 남았군.","JPN":"これで……最後の段階だけが残っているな。","ENG":"With this... only the last step remains.","TWN":"接下來……只剩下最後一步了。"},"stage":{"bg":"MAINSTREAM_000002","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HIVE_VOICE_NULL_NULL","text":{"KOREA":"늑대가 왕좌로 진입합니다.","JPN":"オオカミが王座に進入します。","ENG":"The Wolf is approaching the throne.","TWN":"觀測到狼已接近王座。"},"stage":{"bg":"BLACK","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L45_1","type":"dialog","speaker":"ROSARIA_FALLEN_NAME_QM","text":{"KOREA":"참 오래도 기다리게 하는구나.","JPN":"まったく、ずいぶんと待たせるのじゃな。","ENG":"I almost thought no one was coming.","TWN":"等好久喔。"},"stage":{"bg":"THRONE","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ROSARIA_FALLEN_NAME_QM","text":{"KOREA":"여기까지 다다를 정도의 실력이라면…","JPN":"ここまでたどり着くほどの実力なら……","ENG":"To be skilled enough to reach here can only mean...","TWN":"你有實力能到達這裡……"},"stage":{"bg":"THRONE","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ROSARIA_FALLEN_NAME_CHANGE","text":{"KOREA":"분명 날 즐겁게 해줄 수 있다는 뜻이겠지?","JPN":"きっと妾を楽しませてくれるということであろう。","ENG":"You will be able to entertain me, right?","TWN":"說明一定能讓我開心一下的吧？對吧？"},"stage":{"bg":"THRONE","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"잡담이나 하려고 기다린 건 아니잖아?","JPN":"おしゃべりでもしようと待っていたわけじゃないでしょ？","ENG":"You didn't wait for me just to chat, did you?","TWN":"你等在這裡不是為了閒聊的吧？"},"stage":{"bg":"THRONE","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"WOLF_NPC_PAST_NULL","text":{"KOREA":"그럼 잔말 말고 덤벼.","JPN":"だったら、余計なこと言ってないでさっさとかかって来い。","ENG":"So, shut up and come at me.","TWN":"那就別廢話，上吧。"},"stage":{"bg":"THRONE","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ROSARIA_FALLEN_NAME_CHANGE","text":{"KOREA":"좋은 기백이다, 늑대.","JPN":"良い気迫じゃ、オオカミ。","ENG":"I commend your spirit, Wolf.","TWN":"真是好氣魄，狼。"},"stage":{"bg":"THRONE","bgm":"THEMA_HERO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NAME_CHANGE","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};